package main
import "sync"

func worker(wg *sync.WaitGroup) {
	defer wg.Done()
	// perform work
}

func main() {
	var wg sync.WaitGroup
	wg.Add(1)
	go worker(&wg)
	wg.Wait()
}

package main
import ("errors"; "fmt")

func compute(val int) (int, error) {
	if val < 0 { return 0, errors.New("negative") }
	return val * 2, nil
}

func main() {
	res, err := compute(-1)
	if err != nil {
		fmt.Println(err)
	}
}

